// Google Trends + People Also Ask via SerpAPI
const input = $input.first().json;
const keywords = input.keywords || [];
const runId = input.run_id;
const projectId = input.project_id;
const limit = 10;
const results = [];

// SerpAPI for People Also Ask
try {
  for (const kw of keywords.slice(0, 3)) {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://serpapi.com/search.json?q=${encodeURIComponent(kw)}&api_key=${process.env.SERPAPI_KEY}&engine=google`,
    });

    // People Also Ask
    const paa = resp?.related_questions || [];
    for (const q of paa.slice(0, 3)) {
      results.push({
        run_id: runId,
        project_id: projectId,
        source: 'google_trends',
        raw_text: q.question || '',
        source_url: q.link || `https://google.com/search?q=${encodeURIComponent(q.question || kw)}`,
        engagement_score: 100, // PAA questions have high implicit interest
        metadata: { type: 'people_also_ask', keyword: kw, snippet: q.snippet?.substring(0, 200) },
      });
    }

    // Related searches
    const related = resp?.related_searches || [];
    for (const r of related.slice(0, 2)) {
      results.push({
        run_id: runId,
        project_id: projectId,
        source: 'google_trends',
        raw_text: r.query || '',
        source_url: r.link || `https://google.com/search?q=${encodeURIComponent(r.query || '')}`,
        engagement_score: 50, // Related searches = moderate interest
        metadata: { type: 'related_search', keyword: kw },
      });
    }
  }
} catch (e) {
  return [{ json: { source: 'google_trends', success: false, error: e.message, count: 0 } }];
}

const top10 = results.slice(0, limit);
if (top10.length > 0) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${process.env.SUPABASE_URL}/rest/v1/research_results`,
    headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    body: JSON.stringify(top10),
  });
}

return [{ json: { source: 'google_trends', success: true, count: top10.length } }];
